const body = $input.first().json.body || $input.first().json || {};
const THRESHOLD = 75;
const ALGO_ADDRESS_REGEX = /^[A-Z2-7]{58}$/;

if (!body.taskTitle || !body.taskType || !body.receiverAddress) {
  return [{ json: { ok: false, message: 'taskTitle, taskType, and receiverAddress are required.' } }];
}

if (!ALGO_ADDRESS_REGEX.test(String(body.receiverAddress).trim())) {
  return [{ json: { ok: false, message: 'receiverAddress must be a valid Algorand address.' } }];
}

const normalized = {
  taskTitle: String(body.taskTitle).trim(),
  taskType: String(body.taskType).trim(),
  taskBudget: Number(body.taskBudget || 0),
  receiverAddress: String(body.receiverAddress).trim(),
};

return [{
  json: {
    ...normalized,
    threshold: THRESHOLD,
    prompt: `You are a professional payout decision maker for a blockchain task marketplace.

Your job is to decide whether a submitted task is worth paying for. Evaluate the task as a disciplined operations and delivery reviewer. Focus on:
- business value
- impact
- execution complexity
- clarity of deliverables
- ease of verification
- whether the payout appears justified

Return STRICT JSON only with these keys:
- should_pay (boolean)
- score (number from 0 to 100)
- reason (string)
- summary (string)
- factors (array of short strings)

Rules:
- If should_pay is true, score must be >= ${THRESHOLD}.
- If should_pay is false, score must be < ${THRESHOLD}.
- The summary must explicitly say PAY or DO NOT PAY.
- Be decisive and professional, not vague.

Task title: ${normalized.taskTitle}
Task type: ${normalized.taskType}
Budget ALGO: ${normalized.taskBudget}
Receiver address: ${normalized.receiverAddress}`
  }
}];

const THRESHOLD = 75;
const incoming = $('Analyze Input').first().json || {};
const raw = $input.first().json.text || $input.first().json.response || $input.first().json.output || $input.first().json.message || '{}';

let parsed;
try {
  parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch {
  return [{ json: { ok: false, message: 'Model returned invalid JSON.' } }];
}

let score = Number(parsed.score);
const shouldPay = parsed.should_pay === true;
if (!Number.isFinite(score)) {
  score = shouldPay ? THRESHOLD + 5 : THRESHOLD - 5;
}

score = Math.max(0, Math.min(100, score));
if (shouldPay && score < THRESHOLD) score = THRESHOLD;
if (!shouldPay && score >= THRESHOLD) score = THRESHOLD - 1;

const status = score > THRESHOLD ? 'completed' : (score === THRESHOLD ? 'completed' : 'failed');
const decision = status === 'completed' ? 'pay' : 'skip';
const decisionReason = String(parsed.reason || '').trim() || (status === 'completed'
  ? 'AI judged this task valuable enough to justify payment.'
  : 'AI judged this task insufficiently valuable or verifiable for payment.');
const summary = String(parsed.summary || '').trim() || (status === 'completed'
  ? `AI decision: PAY. ${decisionReason} Score ${score}/100 (threshold ${THRESHOLD}).`
  : `AI decision: DO NOT PAY. ${decisionReason} Score ${score}/100 (threshold ${THRESHOLD}).`);
const factors = Array.isArray(parsed.factors)
  ? parsed.factors.map((item) => String(item)).filter(Boolean).slice(0, 6)
  : [];

return [{
  json: {
    ok: true,
    analysis: {
      score,
      status,
      decision,
      verdict: status === 'completed' ? 'Threshold passed' : 'Threshold not met',
      decisionReason,
      summary,
      factors,
      source: 'n8n-openai',
      taskTitle: incoming.taskTitle,
      taskType: incoming.taskType,
      taskBudget: incoming.taskBudget,
      receiverAddress: incoming.receiverAddress
    }
  }
}];

const body = $input.first().json.body || $input.first().json || {};
const THRESHOLD = 75;

if (!body.taskId || !body.receiver || body.score === undefined) {
  return [{ json: { ok: false, message: 'taskId, receiver, and score are required.' } }];
}

if (Number(body.score) < THRESHOLD || body.status !== 'completed') {
  return [{
    json: {
      ok: true,
      skipped: true,
      message: Number(body.score) < THRESHOLD
        ? `Score ${body.score} is below the payment threshold of ${THRESHOLD}. Payment declined.`
        : 'Task status is not completed. Payment declined.',
      note: {
        taskId: String(body.taskId),
        score: Number(body.score),
        status: String(body.status || 'failed'),
      },
      receiverAddress: String(body.receiver).trim(),
    }
  }];
}

return [{
  json: {
    taskId: String(body.taskId),
    receiver: String(body.receiver).trim(),
    score: Number(body.score),
    status: String(body.status),
    amountAlgo: Number(body.amountAlgo || 0.1),
  }
}];

const paymentGate = $('Payment Gate').first().json || {};
const service = $input.first().json || {};

if (paymentGate.skipped) {
  return [{ json: paymentGate }];
}

if (service.skipped) {
  return [{
    json: {
      ok: true,
      skipped: true,
      message: service.message || 'Payment declined.',
      note: service.note || {
        taskId: paymentGate.taskId,
        score: paymentGate.score,
        status: paymentGate.status,
      },
      receiverAddress: service.receiverAddress || paymentGate.receiver,
    }
  }];
}

const txId = service.transactionId || service.txId || '';
if (!txId) {
  return [{
    json: {
      ok: false,
      message: service.message || 'Algorand API did not return a transaction id.',
      serviceResponse: service,
    }
  }];
}

return [{
  json: {
    ok: true,
    skipped: false,
    transactionId: txId,
    explorerUrl: service.explorerUrl || `https://testnet.explorer.perawallet.app/tx/${txId}`,
    confirmedRound: service.confirmedRound || service.round || 0,
    note: service.note || {
      taskId: paymentGate.taskId,
      score: paymentGate.score,
      status: paymentGate.status,
    },
    receiverAddress: service.receiverAddress || paymentGate.receiver,
  }
}];
